import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { Eye, EyeOff, Zap, ArrowRight } from 'lucide-react';
import './SignInPage.css';

const SignInPage = () => {
  const navigate = useNavigate();
  const { login } = useApp();
  const [form, setForm] = useState({ email: '', password: '' });
  const [errors, setErrors] = useState({});
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);

  const validate = () => {
    const errs = {};
    if (!form.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
      errs.email = 'Please enter a valid email address.';
    }
    if (!form.password || form.password.length <= 6) {
      errs.password = 'Password must be more than 6 characters.';
    }
    return errs;
  };

  const handleSubmit = () => {
    const errs = validate();
    if (Object.keys(errs).length > 0) {
      setErrors(errs);
      return;
    }
    setLoading(true);
    setTimeout(() => {
      login(form.email);
      navigate('/templates');
    }, 900);
  };

  const handleChange = (e) => {
    setForm(prev => ({ ...prev, [e.target.name]: e.target.value }));
    if (errors[e.target.name]) setErrors(prev => ({ ...prev, [e.target.name]: '' }));
  };

  return (
    <div className="signin-page">
      <div className="signin-bg-orb orb-1" />
      <div className="signin-bg-orb orb-2" />

      <div className="signin-card animate-fadeInUp">
        <div className="signin-logo">
          <div className="brand-icon-lg">
            <Zap size={22} />
          </div>
          <span className="brand-name-lg">SkillFolio</span>
        </div>

        <h1 className="signin-title">Welcome Back</h1>
        <p className="signin-subtitle">Sign in to continue building your resume</p>

        <div className="signin-form">
          <div className="form-group">
            <label className="form-label">Email Address</label>
            <input
              type="email"
              name="email"
              className={`form-input ${errors.email ? 'input-error' : ''}`}
              placeholder="you@example.com"
              value={form.email}
              onChange={handleChange}
              onKeyDown={e => e.key === 'Enter' && handleSubmit()}
            />
            {errors.email && <span className="field-error">{errors.email}</span>}
          </div>

          <div className="form-group">
            <label className="form-label">Password</label>
            <div className="password-wrap">
              <input
                type={showPass ? 'text' : 'password'}
                name="password"
                className={`form-input ${errors.password ? 'input-error' : ''}`}
                placeholder="Enter your password (min 7 characters)"
                value={form.password}
                onChange={handleChange}
                onKeyDown={e => e.key === 'Enter' && handleSubmit()}
              />
              <button
                type="button"
                className="show-pass-btn"
                onClick={() => setShowPass(!showPass)}
              >
                {showPass ? <EyeOff size={17} /> : <Eye size={17} />}
              </button>
            </div>
            {errors.password && <span className="field-error">{errors.password}</span>}
          </div>

          <button
            className="btn-primary signin-btn"
            onClick={handleSubmit}
            disabled={loading}
          >
            {loading ? (
              <span className="signin-loading">
                <span className="loader-dot" /><span className="loader-dot" /><span className="loader-dot" />
              </span>
            ) : (
              <>Sign In <ArrowRight size={17} /></>
            )}
          </button>
        </div>

        <p className="signin-footer-note">
          By signing in, you agree to our Terms of Service and Privacy Policy.
        </p>
      </div>
    </div>
  );
};

export default SignInPage;
